  .oai-icon {
    width: 18px;
    height: 18px;
    color: #202123;
    stroke: #202123;
    stroke-width: 2;
  }

  /* Tipografía - jerarquía limpia OpenAI */
  .oai-title {
    font-size: 1rem;
    line-height: 1.4;
    font-weight: 500;
    color: var(--oai-fg);
    margin: 0;
    letter-spacing: -0.01em;
