  .oai-arrow {
    position: absolute;
    top: 1.25rem;
    right: 1.25rem;
    width: 28px;
    height: 28px;
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    opacity: 0;
    transform: translate(-4px, 4px);
    transition: opacity 200ms ease, transform 200ms ease, background 200ms ease;
