    opacity: 1;
    transform: translate(0, 0);
    background: #f4f4f5;
  }

  .oai-arrow-icon {
    width: 14px;
    height: 14px;
    color: var(--oai-fg);
    stroke: var(--oai-fg);
    stroke-width: 2;
